/// Module for graceful degradation patterns.
pub struct GracefulDegradation {
    pub sidebar_available: bool,
    pub agent_list_available: bool,
    pub diff_viewer_available: bool,
}

impl GracefulDegradation {
    pub fn new() -> Self {
        Self {
            sidebar_available: true,
            agent_list_available: true,
            diff_viewer_available: true,
        }
    }

    /// Simulate failure of a non-critical component
    pub fn fail_sidebar(&mut self) {
        self.sidebar_available = false;
        // Main content should still work
    }

    /// Check if main content should render
    pub fn should_render_main_content(&self) -> bool {
        // Core functionality always available
        true
    }

    /// Get sidebar state with fallback
    pub fn get_sidebar_content(&self) -> Option<String> {
        if self.sidebar_available {
            Some("Sidebar content".to_string())
        } else {
            None  // Main content takes full width
        }
    }
}
